package com.izonehub.stores.audit;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;
@Entity public class AuditLog{@Id @GeneratedValue(strategy=GenerationType.UUID) private UUID id;@Column(nullable=false) private String entityType;@Column(nullable=false) private String entityId;@Column(nullable=false) private String action;@Column(columnDefinition="text") private String oldState;@Column(columnDefinition="text") private String newState;@Column(nullable=false) private String performedBy;@Column(nullable=false) private Instant performedAt=Instant.now();protected AuditLog(){} public AuditLog(String entityType,String entityId,String action,String oldState,String newState,String performedBy){this.entityType=entityType;this.entityId=entityId;this.action=action;this.oldState=oldState;this.newState=newState;this.performedBy=performedBy;} public String getAction(){return action;} public String getEntityType(){return entityType;}}
